<script setup lang="ts">
import { ref, computed, watch } from 'vue';
import TheHeader from '../components/TheHeader.vue';
import AppTabs, { type Tab } from '../components/AppTabs.vue';
import { useUserStore } from '../stores/user'; 
import { useReportsStore } from '../stores/reports'; 

import PerformanceReport from '../components/reports/PerformanceReport.vue';
import SessionsReport from '../components/reports/SessionsReport.vue';
import IntervenantsReport from '../components/reports/IntervenantsReport.vue';
import ClientsReport from '../components/reports/ClientsReport.vue';
import AbsencesReport from '../components/reports/AbsencesReport.vue';
import DevisReport from '../components/reports/DevisReport.vue';
import FacturesReport from '../components/reports/FacturesReport.vue';

import IncidentsReport from '../components/reports/IncidentsReport.vue';


const userStore = useUserStore(); 
const reportsStore = useReportsStore();
const activeTab = ref('performance');

const ecoleIdToFetch = computed(() => {
  if (userStore.userRole === 'admin' && userStore.adminSelectedContext) {
    return userStore.adminSelectedContext._id;
  }
  if (userStore.userRole === 'ecole' && userStore.user.associatedEntity) {
    return userStore.user.associatedEntity._id;
  }
  return null; 
});

const etablissementName = computed(() => {
  if (userStore.adminSelectedContext && userStore.userRole === 'admin') {
    return userStore.adminSelectedContext.nom;
  }
  if (userStore.userRole === 'ecole' && userStore.user.associatedEntity) {
    return userStore.user.associatedEntity.nom;
  }
  return '';
});

watch(ecoleIdToFetch, (newId, oldId) => {
  if (newId === oldId) return;

  reportsStore.resetReportsState(); 
  if (newId) {
    switch (activeTab.value) {
      case 'performance':
        reportsStore.fetchPerformanceReport(newId);
        break;
      case 'sessions':
        break;
      case 'intervenants':
        break;
      case 'clients':
        break;
      case 'absences':
        break;
      case 'incidents':
        break;
      case 'devis':
        break;
      case 'factures':
        break;
    }
  }
}, { immediate: true });

watch(activeTab, (newTabId) => {
  if (ecoleIdToFetch.value) {
    switch (newTabId) {
      case 'performance':
        if (!reportsStore.performanceData) reportsStore.fetchPerformanceReport(ecoleIdToFetch.value);
        break;
      case 'sessions':
        break;
      case 'intervenants':
        break;
      case 'clients':
        break;
      case 'absences':
        break;
      case 'incidents':
        break;
      case 'devis':
        break;
      case 'factures':
        break;
    }
  }
});


